import React from 'react';
import { Dashboard } from './Dashboard';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '32rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Render Optimization</h1>
      <Dashboard />
    </div>
  );
}

import React, { useState, useRef } from 'react';
import './styles.css';

// TODO: Break into separate memoized components
// TODO: Use useCallback for handlers
// TODO: Isolate state so sections don't re-render unnecessarily

let nextId = 1;

export const Dashboard: React.FC = () => {
  const [items, setItems] = useState<{ id: number; text: string }[]>([]);
  const [filter, setFilter] = useState('');
  const filterRenders = useRef(0);
  const listRenders = useRef(0);
  const counterRenders = useRef(0);

  // These increment every render — all sections re-render together
  filterRenders.current++;
  listRenders.current++;
  counterRenders.current++;

  // BUG: New function every render — memo won't help
  const addItem = () => {
    setItems(prev => [...prev, { id: nextId++, text: `Item ${nextId}` }]);
  };

  const clearItems = () => {
    setItems([]);
  };

  const filtered = items.filter(item =>
    item.text.toLowerCase().includes(filter.toLowerCase())
  );

  return (
    <div className="opt-dashboard">
      {/* Counter Section */}
      <div className="opt-section">
        <div className="opt-section__header">
          <h2>Counter</h2>
          <span data-testid="counter-renders" className="opt-renders">
            renders: {counterRenders.current}
          </span>
        </div>
        <p data-testid="item-count" className="opt-count">{items.length} items</p>
        <div className="opt-actions">
          <button data-testid="add-btn" className="opt-btn" onClick={addItem}>Add Item</button>
          <button data-testid="clear-btn" className="opt-btn opt-btn--secondary" onClick={clearItems}>Clear</button>
        </div>
      </div>

      {/* Filter Section */}
      <div className="opt-section">
        <div className="opt-section__header">
          <h2>Filter</h2>
          <span data-testid="filter-renders" className="opt-renders">
            renders: {filterRenders.current}
          </span>
        </div>
        <input
          data-testid="filter-input"
          className="opt-input"
          value={filter}
          onChange={e => setFilter(e.target.value)}
          placeholder="Filter items…"
        />
      </div>

      {/* List Section */}
      <div className="opt-section">
        <div className="opt-section__header">
          <h2>Items</h2>
          <span data-testid="list-renders" className="opt-renders">
            renders: {listRenders.current}
          </span>
        </div>
        <div data-testid="item-list" className="opt-list">
          {filtered.map(item => (
            <div key={item.id} className="opt-list__item">{item.text}</div>
          ))}
          {filtered.length === 0 && <p className="opt-empty">No items</p>}
        </div>
      </div>
    </div>
  );
};

.opt-dashboard {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.opt-section {
  padding: 1rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  background: white;
}

.opt-section__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.75rem;
}

.opt-section__header h2 {
  font-size: 0.9375rem;
  font-weight: 600;
  margin: 0;
}

.opt-renders {
  font-size: 0.6875rem;
  color: #9ca3af;
  font-variant-numeric: tabular-nums;
}

.opt-count {
  font-size: 1.25rem;
  font-weight: 700;
  margin-bottom: 0.75rem;
}

.opt-actions {
  display: flex;
  gap: 0.5rem;
}

.opt-btn {
  padding: 0.375rem 0.75rem;
  border: none;
  border-radius: 0.375rem;
  background: #3b82f6;
  color: white;
  font-size: 0.8125rem;
  cursor: pointer;
}

.opt-btn:hover {
  background: #2563eb;
}

.opt-btn--secondary {
  background: #6b7280;
}

.opt-btn--secondary:hover {
  background: #4b5563;
}

.opt-input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.opt-list {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  max-height: 12rem;
  overflow-y: auto;
}

.opt-list__item {
  padding: 0.375rem 0.5rem;
  background: #f9fafb;
  border-radius: 0.25rem;
  font-size: 0.8125rem;
}

.opt-empty {
  color: #9ca3af;
  font-size: 0.8125rem;
}

