import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Render Batching Optimization', () => {
  it('renders all sections', () => {
    render(<App />);
    expect(screen.getByTestId('item-count')).toBeInTheDocument();
    expect(screen.getByTestId('filter-input')).toBeInTheDocument();
    expect(screen.getByTestId('item-list')).toBeInTheDocument();
  });

  it('adding an item updates count', () => {
    render(<App />);
    expect(screen.getByTestId('item-count')).toHaveTextContent('0');
    fireEvent.click(screen.getByTestId('add-btn'));
    expect(screen.getByTestId('item-count')).toHaveTextContent('1');
  });

  it('clear removes all items', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('add-btn'));
    fireEvent.click(screen.getByTestId('add-btn'));
    fireEvent.click(screen.getByTestId('clear-btn'));
    expect(screen.getByTestId('item-count')).toHaveTextContent('0');
  });

  it('filter input filters items', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('add-btn'));
    fireEvent.click(screen.getByTestId('add-btn'));
    fireEvent.change(screen.getByTestId('filter-input'), { target: { value: 'zzzzz' } });
    expect(screen.getByTestId('item-list').children.length).toBeLessThanOrEqual(1);
  });

  it('filter section does NOT re-render when adding items', () => {
    render(<App />);
    const filterBefore = screen.getByTestId('filter-renders').textContent;
    fireEvent.click(screen.getByTestId('add-btn'));
    fireEvent.click(screen.getByTestId('add-btn'));
    const filterAfter = screen.getByTestId('filter-renders').textContent;
    expect(filterAfter).toBe(filterBefore);
  });

  it('counter section does NOT re-render when filtering', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('add-btn'));
    const counterBefore = screen.getByTestId('counter-renders').textContent;
    fireEvent.change(screen.getByTestId('filter-input'), { target: { value: 'a' } });
    const counterAfter = screen.getByTestId('counter-renders').textContent;
    expect(counterAfter).toBe(counterBefore);
  });

  it('render counts are displayed', () => {
    render(<App />);
    expect(screen.getByTestId('filter-renders')).toBeInTheDocument();
    expect(screen.getByTestId('list-renders')).toBeInTheDocument();
    expect(screen.getByTestId('counter-renders')).toBeInTheDocument();
  });
});

