import React, { useState, useRef, useCallback, memo, useMemo } from 'react';
import './styles.css';

let nextId = 1;

interface Item {
  id: number;
  text: string;
}

/* ---------- Counter Section ---------- */
interface CounterSectionProps {
  count: number;
  onAdd: () => void;
  onClear: () => void;
}

const CounterSection = memo<CounterSectionProps>(({ count, onAdd, onClear }) => {
  const renders = useRef(0);
  renders.current++;
  return (
    <div className="opt-section">
      <div className="opt-section__header">
        <h2>Counter</h2>
        <span data-testid="counter-renders" className="opt-renders">renders: {renders.current}</span>
      </div>
      <p data-testid="item-count" className="opt-count">{count} items</p>
      <div className="opt-actions">
        <button data-testid="add-btn" className="opt-btn" onClick={onAdd}>Add Item</button>
        <button data-testid="clear-btn" className="opt-btn opt-btn--secondary" onClick={onClear}>Clear</button>
      </div>
    </div>
  );
});

/* ---------- Filter Section ---------- */
interface FilterSectionProps {
  value: string;
  onChange: (v: string) => void;
}

const FilterSection = memo<FilterSectionProps>(({ value, onChange }) => {
  const renders = useRef(0);
  renders.current++;
  return (
    <div className="opt-section">
      <div className="opt-section__header">
        <h2>Filter</h2>
        <span data-testid="filter-renders" className="opt-renders">renders: {renders.current}</span>
      </div>
      <input
        data-testid="filter-input"
        className="opt-input"
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder="Filter items…"
      />
    </div>
  );
});

/* ---------- List Section ---------- */
interface ListSectionProps {
  items: Item[];
}

const ListSection = memo<ListSectionProps>(({ items }) => {
  const renders = useRef(0);
  renders.current++;
  return (
    <div className="opt-section">
      <div className="opt-section__header">
        <h2>Items</h2>
        <span data-testid="list-renders" className="opt-renders">renders: {renders.current}</span>
      </div>
      <div data-testid="item-list" className="opt-list">
        {items.map(item => (
          <div key={item.id} className="opt-list__item">{item.text}</div>
        ))}
        {items.length === 0 && <p className="opt-empty">No items</p>}
      </div>
    </div>
  );
});

/* ---------- Dashboard ---------- */
export const Dashboard: React.FC = () => {
  const [items, setItems] = useState<Item[]>([]);
  const [filter, setFilter] = useState('');

  const addItem = useCallback(() => {
    setItems(prev => [...prev, { id: nextId++, text: `Item ${nextId}` }]);
  }, []);

  const clearItems = useCallback(() => {
    setItems([]);
  }, []);

  const handleFilterChange = useCallback((v: string) => {
    setFilter(v);
  }, []);

  const filtered = useMemo(
    () => items.filter(item => item.text.toLowerCase().includes(filter.toLowerCase())),
    [items, filter]
  );

  return (
    <div className="opt-dashboard">
      <CounterSection count={items.length} onAdd={addItem} onClear={clearItems} />
      <FilterSection value={filter} onChange={handleFilterChange} />
      <ListSection items={filtered} />
    </div>
  );
};
